import psycopg2

def search_users(**kwargs):
    conn = psycopg2.connect(
        host="localhost",
        database="your_database",
        user="your_username",
        password="your_password"
    )
    cur = conn.cursor()

    query = "SELECT * FROM users WHERE "
    conditions = []

    for key, value in kwargs.items():
        if key == 'username':
            conditions.append(f"username = '{value}'")
        elif key == 'email':
            conditions.append(f"email = '{value}'")
        elif key == 'role':
            conditions.append(f"role = '{value}'")
        elif key == 'status':
            conditions.append(f"status = '{value}'")

    if conditions:
        query += " AND ".join(conditions)

    cur.execute(query)
    rows = cur.fetchall()

    return rows

